import {
    CategoryResource,
    CommentsResource,
    PhotoResource
} from "./types.ts";

type TemplateFunction = (context: unknown) => string;

declare const Handlebars: {
    compile(template: string): TemplateFunction;
};

export function displayPicture(data: PhotoResource): void {
    const templateElement = document.querySelector("#photoTemplate") as HTMLScriptElement;
    const template = Handlebars.compile(templateElement.innerHTML);
    const html = template(data);

    const photoSection = document.querySelector("#la_photo") as HTMLElement;
    photoSection.innerHTML = html;
}

export function displayCategory(data: CategoryResource): void {
    const categorie = document.querySelector("#la_categorie") as HTMLElement;
    const descr = document.querySelector("#categorie_descr") as HTMLElement;

    categorie.textContent = `categorie : ${data.categorie.nom}`;
    descr.textContent = data.categorie.descr;
}

export function displayComments(data: CommentsResource): void {
    const liste = document.querySelector("#les_commentaires") as HTMLUListElement;
    liste.innerHTML = "";

    data.comments.forEach((comment) => {
        const li = document.createElement("li");
        li.textContent = `${comment.pseudo} : ${comment.content}`;
        liste.appendChild(li);
    });
}