import loadPicture, { loadResource } from "./photoloader.ts";
import { displayCategory, displayComments, displayPicture } from "./ui.ts";
import { first, last, load, next, prev } from "./gallery.ts";
import { displayGallery } from "./gallery_ui.ts";
import {
    CategoryResource,
    CommentsResource,
    PhotoCollection,
    PhotoResource
} from "./types.ts";

function handleError(err: unknown): void {
    if (err instanceof Error) {
        console.log(err.message);
    }
}

function getCategory(data: PhotoResource): Promise<CategoryResource> {
    return loadResource<CategoryResource>(data.links.categorie.href);
}

function getComments(data: PhotoResource): Promise<CommentsResource> {
    return loadResource<CommentsResource>(data.links.comments.href);
}

function getPicture(id: number): void {
    loadPicture(id)
        .then((data) => {
            displayPicture(data);

            getCategory(data)
                .then((categorie) => {
                    displayCategory(categorie);
                })
                .catch(handleError);

            getComments(data)
                .then((comments) => {
                    displayComments(comments);
                })
                .catch(handleError);
        })
        .catch(handleError);
}

function refreshGallery(action: () => Promise<PhotoCollection>): void {
    action()
        .then((galerie) => {
            displayGallery(galerie, getPicture);
        })
        .catch(handleError);
}

const boutonLoad = document.querySelector("#load") as HTMLButtonElement;
const boutonNext = document.querySelector("#next") as HTMLButtonElement;
const boutonPrev = document.querySelector("#prev") as HTMLButtonElement;
const boutonFirst = document.querySelector("#first") as HTMLButtonElement;
const boutonLast = document.querySelector("#last") as HTMLButtonElement;

boutonLoad.addEventListener("click", () => {
    refreshGallery(load);
});

boutonNext.addEventListener("click", () => {
    refreshGallery(next);
});

boutonPrev.addEventListener("click", () => {
    refreshGallery(prev);
});

boutonFirst.addEventListener("click", () => {
    refreshGallery(first);
});

boutonLast.addEventListener("click", () => {
    refreshGallery(last);
});

getPicture(
    window.location.hash
        ? Number(window.location.hash.slice(1))
        : 105
);