import apiRoot, { apiBase } from "./config.ts";
import { PhotoResource } from "./types.ts";

function buildUrl(uri: string): string {
    if (uri.startsWith("http://") || uri.startsWith("https://")) {
        return uri;
    }

    if (uri.startsWith("/www/")) {
        return apiBase + uri;
    }

    if (uri.startsWith("/")) {
        return apiBase + apiRoot + uri;
    }

    return apiBase + apiRoot + "/" + uri;
}

export default function loadPicture(idPicture: number): Promise<PhotoResource> {
    return loadResource<PhotoResource>(`${apiRoot}/photos/${idPicture}`);
}

export function loadResource<T>(uri: string): Promise<T> {
    return fetch(buildUrl(uri), {
        credentials: "include"
    })
        .then((response: Response) => {
            if (!response.ok) {
                return Promise.reject(new Error(response.statusText));
            }
            return response.json() as Promise<T>;
        })
        .catch((err: unknown) => {
            if (err instanceof Error) {
                console.log(err.message);
            }
            return Promise.reject(err);
        });
}