import { PhotoCollection } from "./types.ts";

type TemplateFunction = (context: unknown) => string;

declare const Handlebars: {
    compile(template: string): TemplateFunction;
};

export function displayGallery(galerie: PhotoCollection, onPhotoClick: (id: number) => void): void {
    const templateElement = document.querySelector("#galleryTemplate") as HTMLScriptElement;
    const template = Handlebars.compile(templateElement.innerHTML);
    const html = template({ photos: galerie.photos });

    const container = document.querySelector("#les_photos") as HTMLElement;
    container.innerHTML = html;

    container.querySelectorAll(".vignette").forEach((vignette) => {
        vignette.addEventListener("click", () => {
            const id = Number((vignette as HTMLElement).dataset.photoId);
            onPhotoClick(id);
        });
    });
}