import apiRoot from "./config.ts";
import { loadResource } from "./photoloader.ts";
import { PhotoCollection } from "./types.ts";

let currentGallery: PhotoCollection | null = null;

function loadGalleryFromUri(uri: string): Promise<PhotoCollection> {
    return loadResource<PhotoCollection>(uri).then((gallery) => {
        currentGallery = gallery;
        return gallery;
    });
}

export function load(): Promise<PhotoCollection> {
    return loadGalleryFromUri(`${apiRoot}/photos`);
}

export function next(): Promise<PhotoCollection> {
    if (currentGallery === null) {
        return load();
    }
    return loadGalleryFromUri(currentGallery.links.next.href);
}

export function prev(): Promise<PhotoCollection> {
    if (currentGallery === null) {
        return load();
    }
    return loadGalleryFromUri(currentGallery.links.prev.href);
}

export function first(): Promise<PhotoCollection> {
    if (currentGallery === null) {
        return load();
    }
    return loadGalleryFromUri(currentGallery.links.first.href);
}

export function last(): Promise<PhotoCollection> {
    if (currentGallery === null) {
        return load();
    }
    return loadGalleryFromUri(currentGallery.links.last.href);
}